// 1. Получаем данные
const config = $('Get mortrage data').item.json;

const loanAmount = config.mashkanta_amount;
const totalMonths = config.years * 12;
const fixedInterestRate = config.fixed_rate;

// Параметры погашения
const mihzurAmount = config.mihzur_amount || 0; 
const mihzurMonth = config.mihzur_month || 0;
// ТИП СОКРАЩЕНИЯ: 'Tashlum' (платеж) или 'Tkufa' (срок)
const reductionType = config.mihzur_type || 'Tkufa'; 

const monthlyRate = (fixedInterestRate / 100) / 12;

let remainingBalance = loanAmount;
let totalPaidSum = 0;
let currentMonthlyPayment = 0; // Для фиксации платежа при сокращении срока
const paymentSchedule = [];

for (let month = 1; month <= totalMonths; month++) {
  const monthsLeft = totalMonths - month + 1;

  let monthlyPayment;

  if (reductionType === 'Tkufa' && month > mihzurMonth && currentMonthlyPayment > 0) {
      // Стратегия: Сокращение срока. Используем платеж, который был ДО погашения.
      monthlyPayment = currentMonthlyPayment;
  } else {
      // Стратегия: Уменьшение платежа (пересчет по Шпицеру)
      monthlyPayment = remainingBalance * (monthlyRate * Math.pow(1 + monthlyRate, monthsLeft)) / 
                       (Math.pow(1 + monthlyRate, monthsLeft) - 1);
  }

  const interestPayment = remainingBalance * monthlyRate;
  const principalPayment = Math.min(monthlyPayment - interestPayment, remainingBalance);

  // Запоминаем платеж ПЕРЕД погашением для стратегии 'Tkufa'
  if (month === mihzurMonth) {
      currentMonthlyPayment = monthlyPayment;
  }

  // Вычитаем плановое тело
  remainingBalance -= principalPayment;

  // ДОСРОЧНОЕ ПОГАШЕНИЕ
  let actualExtraPayment = 0;
  if (month === mihzurMonth && remainingBalance > 0) {
      actualExtraPayment = Math.min(mihzurAmount, remainingBalance);
      remainingBalance -= actualExtraPayment;
  }

  const totalThisMonth = (principalPayment + interestPayment + actualExtraPayment);
  totalPaidSum += totalThisMonth;

  paymentSchedule.push({
    Month: month,
    Payment: parseFloat(totalThisMonth.toFixed(2)),
    Balance: parseFloat(Math.max(0, remainingBalance).toFixed(2))
  });

  if (remainingBalance <= 0) break;
}

return [{
  json: {
    summary: {
      strategy: reductionType === 'Tkufa' ? "Сокращение срока (Кицур Ткуфа)" : "Уменьшение платежа (Кицур Ташлюм)",
      rateType: "Fixed (Non-Linked)",
      initialLoanAmount: loanAmount,
      totalPaidSum: parseFloat(totalPaidSum.toFixed(2)), // Тоже числом для удобства
      totalOverpayment: parseFloat((totalPaidSum - loanAmount).toFixed(2)),
      actualMonthsDuration: paymentSchedule.length,
      savedMonths: totalMonths - paymentSchedule.length,
      // Теперь это строго число (Number)
      monthlyPayment: parseFloat(paymentSchedule[0].Payment.toFixed(2)) 
    },
    fullSchedule: paymentSchedule
  }
}];

// 1. Данные из узла
const tableData = $('Get mortrage data').item.json; 

const loanAmount = Number(tableData.mashkanta_amount) || 0; 
const years = Number(tableData.years) || 0;
const totalMonths = years * 12;

const mihzurAmount = Number(tableData.mihzur_amount) || 0;
const mihzurMonth = Number(tableData.mihzur_month) || 0;
// Берем тип из таблицы: 'Tkufa' или 'Tashlum'
const reductionType = tableData.mihzur_type || 'Tkufa'; 

// 2. Определяем ставку
let annualRate = 0;
if (tableData.route_type === 'Prime') {
    annualRate = ($json.output && $json.output.prime_rate) ? Number($json.output.prime_rate) : 4.75;
} else {
    annualRate = Number(tableData.nominal_rate_madad) || 4;
}

if (loanAmount <= 0 || totalMonths <= 0 || annualRate <= 0) {
    return { error: "Missing data", debug: { loanAmount, totalMonths, annualRate } };
}

const monthlyRate = (annualRate / 100) / 12;

let remainingBalance = loanAmount;
let schedule = [];
let currentMonthlyPayment = 0;
let totalExtraPaid = 0;

for (let month = 1; month <= totalMonths; month++) {
    const monthsLeft = totalMonths - month + 1;

    // ЛОГИКА РАСЧЕТА ПЛАТЕЖА
    let monthlyPayment;

    if (reductionType === 'Tkufa' && month > mihzurMonth && currentMonthlyPayment > 0) {
        // Если сокращаем СРОК — платим столько же, сколько платили до погашения
        monthlyPayment = currentMonthlyPayment;
    } else {
        // Если уменьшаем ПЛАТЕЖ (или это начало срока) — пересчитываем Шпицера
        monthlyPayment = (remainingBalance * monthlyRate) / (1 - Math.pow(1 + monthlyRate, -monthsLeft));
    }

    const interestComponent = remainingBalance * monthlyRate;
    const principalComponent = Math.min(monthlyPayment - interestComponent, remainingBalance);

    // Запоминаем платеж перед погашением для стратегии 'Tkufa'
    if (month === mihzurMonth) {
        currentMonthlyPayment = monthlyPayment;
    }

    remainingBalance -= principalComponent;

    // Учет досрочного погашения
    let actualMihzur = 0;
    if (month === mihzurMonth && remainingBalance > 0) {
        actualMihzur = Math.min(mihzurAmount, remainingBalance);
        remainingBalance -= actualMihzur;
        totalExtraPaid += actualMihzur;
    }

    schedule.push({
        month: month,
        payment: parseFloat((principalComponent + interestComponent + actualMihzur).toFixed(2)),
        interest: parseFloat(interestComponent.toFixed(2)),
        principal: parseFloat(principalComponent.toFixed(2)),
        remaining: parseFloat(Math.max(0, remainingBalance).toFixed(2))
    });

    if (remainingBalance <= 0) break;
}

const totalPaymentsSum = schedule.reduce((sum, item) => sum + item.payment, 0);

return {
    summary: {
        route_type: tableData.route_type,
        strategy: reductionType === 'Tkufa' ? "Сокращение срока" : "Уменьшение платежа",
        rate_used: annualRate,
        original_loan: loanAmount,
        monthly_payment_start: schedule[0].payment,
        total_paid: parseFloat(totalPaymentsSum.toFixed(2)),
        total_interest: parseFloat((totalPaymentsSum - loanAmount).toFixed(2)),
        actual_months: schedule.length,
        saved_months: totalMonths - schedule.length
    },
    schedule: schedule
};

// 1. Получаем данные
const config = $('Get mortrage data').item.json;
const ratesRaw = $input.first().json.madad_rate || "1.8"; 
const rates = parseFloat(ratesRaw.toString().replace('%', ''));

const loanAmount = config.mashkanta_amount;
const totalMonths = config.years * 12;
const fixedInterestRate = config.nominal_rate_madad;

// Параметры погашения
const mihzurAmount = config.mihzur_amount || 0; 
const mihzurMonth = config.mihzur_month || 0;
// ТИП СОКРАЩЕНИЯ: 'Tkufa' (срок) или 'Tashlum' (платеж)
const reductionType = config.mihzur_type || 'Tkufa'; 

const monthlyInflation = (rates / 100) / 12; 
const monthlyRate = (fixedInterestRate / 100) / 12;

let remainingBalance = loanAmount;
let totalPaidSum = 0;
let currentMonthlyPayment = 0; // Для фиксации платежа при сокращении срока
const paymentSchedule = [];

for (let month = 1; month <= totalMonths; month++) {
  const monthsLeft = totalMonths - month + 1;

  let monthlyPayment;

  // ЛОГИКА ВЫБОРА ТИПА ПОГАШЕНИЯ
  if (reductionType === 'Tkufa' && month > mihzurMonth && currentMonthlyPayment > 0) {
      // Стратегия: Сокращение срока. Платеж растет ТОЛЬКО на инфляцию,
      // но база Шпицера не пересчитывается (остается "высокой").
      monthlyPayment = currentMonthlyPayment;
  } else {
      // Стратегия: Уменьшение платежа или обычный расчет
      monthlyPayment = remainingBalance * (monthlyRate * Math.pow(1 + monthlyRate, monthsLeft)) / 
                       (Math.pow(1 + monthlyRate, monthsLeft) - 1);
  }

  const interestPayment = remainingBalance * monthlyRate;
  const principalPayment = Math.min(monthlyPayment - interestPayment, remainingBalance);

  // Запоминаем платеж ПЕРЕД погашением (нужен для 'Tkufa')
  if (month === mihzurMonth) {
      currentMonthlyPayment = monthlyPayment;
  }

  // 1. Вычитаем плановое тело
  remainingBalance -= principalPayment;

  // 2. ДОСРОЧНОЕ ПОГАШЕНИЕ
  let actualExtraPayment = 0;
  if (month === mihzurMonth && remainingBalance > 0) {
      actualExtraPayment = Math.min(mihzurAmount, remainingBalance);
      remainingBalance -= actualExtraPayment;
  }

  // 3. ИНДЕКСАЦИЯ остатка (Madad)
  remainingBalance = remainingBalance * (1 + monthlyInflation);

  // 4. ИНДЕКСАЦИЯ платежа для следующего месяца (только если это 'Tkufa')
  // В Мададе даже при сокращении срока сам "замороженный" платеж тоже должен индексироваться.
  if (reductionType === 'Tkufa') {
      currentMonthlyPayment = currentMonthlyPayment * (1 + monthlyInflation);
  }

  const totalThisMonth = (principalPayment + interestPayment + actualExtraPayment);
  totalPaidSum += totalThisMonth;

  paymentSchedule.push({
    Month: month,
    Payment: parseFloat(totalThisMonth.toFixed(2)),
    Balance: parseFloat(Math.max(0, remainingBalance).toFixed(2))
  });

  if (remainingBalance <= 0) break;
}

const paymentYear10 = paymentSchedule.find(p => p.Month === 120);

return [{
  json: {
    summary: {
      strategy: reductionType === 'Tkufa' ? "Сокращение срока (Ткуфа)" : "Уменьшение платежа (Ташлюм)",
      initialLoanAmount: loanAmount,
      totalYears: config.years,
      inflationRateUsed: rates + "%",
      totalPaidSum: parseFloat(totalPaidSum.toFixed(2)),
      totalOverpayment: parseFloat((totalPaidSum - loanAmount).toFixed(2)),
      actualMonthsDuration: paymentSchedule.length,
      savedMonths: totalMonths - paymentSchedule.length,
      forecast: {
          start: parseFloat(paymentSchedule[0].Payment.toFixed(2)),
          after10Years: paymentYear10 ? parseFloat(paymentYear10.Payment.toFixed(2)) : "Выплачено",
          final: parseFloat(paymentSchedule[paymentSchedule.length - 1].Payment.toFixed(2))
      }
    },
    fullSchedule: paymentSchedule
  }
}];
